// PT Serif font for jsPDF (Cyrillic support)
var PTSerifRegular = "";
var PTSerifBold = "";

function registerPTSerif(doc) {
    doc.addFileToVFS("PTSerif-Regular.ttf", PTSerifRegular);
    doc.addFont("PTSerif-Regular.ttf", "PTSerif", "normal");
    doc.addFileToVFS("PTSerif-Bold.ttf", PTSerifBold);
    doc.addFont("PTSerif-Bold.ttf", "PTSerif", "bold");
    doc.setFont("PTSerif", "normal");
}
